namespace App\Modules\Vardiya\Requests;

use Illuminate\Foundation\Http\FormRequest;
use Illuminate\Validation\Rule;

class StoreShiftRequest extends FormRequest
{
    public function authorize(): bool { return true; }

    public function rules(): array
    {
        $companyId = auth()->user()->company_id;
        return [
            'name'           => ['required', 'string', 'max:191',
                Rule::unique('shifts')->where('company_id', $companyId)->whereNull('deleted_at')],
            'start_time'     => 'required|date_format:H:i',
            'end_time'       => 'required|date_format:H:i',
            'is_night_shift' => 'nullable|boolean',
            'color'          => 'nullable|string|max:7|regex:/^#[0-9A-Fa-f]{6}$/',
            'breaks'         => 'nullable|array',
            'breaks.*.label'         => 'required_with:breaks|string|max:100',
            'breaks.*.duration_minutes' => 'required_with:breaks|integer|min:1|max:120',
            'is_active'      => 'nullable|boolean',
        ];
    }

    public function messages(): array
    {
        return [
            'name.required'      => 'Vardiya adı zorunludur.',
            'name.unique'        => 'Bu vardiya adı şirketinizde zaten mevcut.',
            'start_time.required'=> 'Başlangıç saati zorunludur.',
            'end_time.required'  => 'Bitiş saati zorunludur.',
        ];
    }
}
